def sort_stack(stack):
    if not stack:
        return

    temp = stack.pop()
    sort_stack(stack)
    _sorted_insert(stack, temp)

def _sorted_insert(stack, element):
    if not stack or element > stack[-1]:
        stack.append(element)
        return

    temp = stack.pop()
    _sorted_insert(stack, element)
    stack.append(temp)
